mapper.select:
WITH dwc_datasets AS ( SELECT DISTINCT de.dataset_key FROM dataset_endpoint de INNER JOIN endpoint e ON e.key = de.endpoint_key WHERE e.type = 'DWC_DP' ), latest AS ( SELECT DISTINCT ON (m.dataset_key) m.dataset_key, m.content_json AS metadata, m.modified FROM metadata m INNER JOIN dwc_datasets d ON d.dataset_key = m.dataset_key WHERE m.content_json IS NOT NULL ORDER BY m.dataset_key, m.modified DESC, m.key DESC ) SELECT latest.dataset_key, ( SELECT e.key FROM endpoint e INNER JOIN dataset_endpoint de ON de.endpoint_key = e.key WHERE de.dataset_key = latest.dataset_key AND e.type = 'DWC_DP'
) AS endpoint_key, latest.modified, jsonb_build_object( 'name', latest.metadata->>'name', 'title', latest.metadata->>'title', 'resources', ( SELECT jsonb_agg(res->>'name') FROM jsonb_array_elements(latest.metadata->'resources') res ) )::text AS metadata FROM latest
LIMIT #{params.limit} OFFSET #{params.offset}
